EXPLAIN ANALYZE
SELECT * FROM users
WHERE created_at = '2023-06-15 10:00:00';

EXPLAIN ANALYZE
SELECT * FROM users
WHERE created_at BETWEEN '2023-06-01' AND '2023-06-30';

CREATE INDEX idx_users_name ON users (last_name, first_name);

EXPLAIN SELECT * FROM users WHERE last_name = 'Smith';

EXPLAIN SELECT * FROM users WHERE first_name = 'Anna';

EXPLAIN ANALYZE
SELECT * FROM users
WHERE created_at > '2000-01-01';
